_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_main, vUv ).xyz;

    // darken (decay) over uTime
    ret *= 0.98; //or try: ret -= 0.004;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

 vec4 fragColor = 0;
 // CONV: Center on screen, then try some uAspect correction
 vUv = (vUv*2) - 1;
 vUv *= uAspect.xy;
 // CONV: Adjust this to flip the output (±vUv.x, ±vUv.y)
 vUv = vec2(vUv.x, -vUv.y);

 vec2 fragCoord  = vUv;
 //vUv = (fragCoord.xy-.5*vUv.xy) / vUv.y;

 vec2 UV = fragCoord.xy/vUv.xy;
 // vec2 UV = vUv;

 // CONV: iMouse unsupported
 // vec3 M = iMouse.xyz/vUv.xyz;
 //vec3 M = tx;
 float f = 0.3;

 // drop flow speed?
 vec3 M = 5;
 // float T = uTime+M.x*2.;
 float T;

 #ifdef HAS_HEART
  //T = mod_conv(uTime, 102.);
  //T = mix(T, M.x*102., M.z>0.?1.:0.);
  //T = mix(T, M.x*102., 0);
  //T = mod(uTime, stime);
  T=mod(uTime, stimetotal);
 #endif

 float t = T*.2;

 // CONV: iMouse unsupported
 //vec3 iMouse = vec3(sin(uTime), sin(uTime), 1);
 //vec3 iMouse = tx;
 vec3 iMouse = 1;

 float rainAmount = iMouse.z>0. ? M.y : sin(T*.05)*.3+.7;

 //float rainAmount = 1;

 float maxBlur = mix(3., 6., rainAmount);
 float minBlur = 2.;

 float story = 0.;
 float heart = 0.;

 #ifdef HAS_HEART
  story = S(0., stime, T);

  t = min(1., T/stime); // remap drop uTime so it goes slower when it freezes
  t = 1.-t;
  t = (1.-t*t)*stime;

  // float zoom= mix(.3, 1.2, story); // slowly zoom out
  float zoom= mix(.4, 1.1, story); // slowly zoom out
  //vUv = vUv*zoom*0.2;

  vUv = vUv*zoom*0.8;

  minBlur = 4.+S(.5, 1., story)*3.; // more opaque glass towards the end
  maxBlur = 6.+S(.5, 1., story)*1.5;

  vec2 hv = vUv-vec2(.0, -.1); // build heart
  hv.x *= .5;
  float s = S(stimetotal, stime, T); // heart gets smaller and fades towards the end
  hv.y-=sqrt(abs(hv.x))*.5*s;
  heart = length(hv);
  heart = S(.4*s, .2*s, heart)*s;

  rainAmount = heart; // the rain is where the heart is
  maxBlur-=heart; // inside the heart slighly less foggy

  vec2 uvtx=vUv*0.2;
  vUv *= 1.5; // zoom out a bit more
  t *= .25;
 #else
  float zoom = -cos(T*.2);
  vUv *= .7+zoom*.3;
 #endif

 UV = (UV-.5)*(.9+zoom*.1)+.5;

 float staticDrops = S(-.5, 1., rainAmount)*2.;
 float layer1 = S(.25, .75, rainAmount);
 float layer2 = S(.0, .5, rainAmount);

 vec2 c = Drops(vUv, t, staticDrops, layer1, layer2);

 #ifdef CHEAP_NORMALS
  vec2 n = vec2(dFdx(c.x), dFdy(c.x));// cheap normals (3x cheaper, but 2 times shittier ;))
 #else
  vec2 e = vec2(.001, 0.);
  float cx = Drops(vUv+e, t, staticDrops, layer1, layer2).x;
  float cy = Drops(vUv+e.yx, t, staticDrops, layer1, layer2).x;
  vec2 n = vec2(cx-c.x, cy-c.x); // expensive normals
 #endif


 #ifdef HAS_HEART
  // drop fading?
  n *= 1.-S(60., 85., T);
  c.y *= 1.-S(80., 100., T)*.8;
 #endif

 float focus = mix(maxBlur-c.y, minBlur, S(.1, .2, c.x));
 // vec3 col = textureLod(iChannel0, UV+n, focus).rgb;
 // vec3 col = iChannel0.SampleLevel(sampler0, UV + n, focus).rgb;
 // vec3 col = textureLod(iChannel0, vec4(vUv+n, 0, focus)).rgb;
 // vec3 col = textureLod(iChannel0, vec4(vUv+n, 0, focus)).rgb;

 // focus=1; n=0;
 //float fac = 2.5;
 float facx = 2.5;
 float facy = 6;
 vec2 flippedUV = vec2(uvtx.x*facx+0.5, 0.5-uvtx.y*facy);
 //vec2 flippedUV = vec2(UV.x+0.5, 0.5-UV.y);

 vec3 col = textureLod(iChannel0, vec4(flippedUV+n, 0, focus)).rgb;

 #ifdef USE_POST_PROCESSING
  t = (T+3.)*.5; // make uTime sync with first lightning
  float colFade = sin(t*.2)*.5+.5+story;
  col *= mix(vec3(1., 1., 1.), vec3(.8, .9, 1.3), colFade); // subtle color shift

  float fade = S(0., 10., T*3); // fade in at the start


//float lightning = sin(t*sin(t*10)); // lighting flicker

// Pseudo-random gate based on uTime
float chaos = fract(sin(floor(t * 0.5) * 12.9898) * 43758.5453); // changes every ~2s
float gate = step(0.1, chaos); // ~15% chance to allow flash

// Smooth flash shape
float flashShape = pow(max(0.0, sin(t + sin(t * 0.5))), 12);

// Lightning intensity
float lightning = sin(t*sin(t*10)) * 0.2; // lighting flicker
lightning *= flashShape * gate;

// Composite
col *= 1.0 + lightning * fade * mix(1.0, 0.1, story * story);

/*  float lightning = sin(t * sin(t * 3.0)) * 0.3;
  lightning *= pow(max(0., sin(t+sin(t))), 10); // lightning flash
*/

  //col *= 1.+lightning*fade*mix(1., .1, story*story); // composite lightning

  #ifdef bass_smooth
   col = col+0.05*(clamp(bass_smooth, 0, 2)-1);
  #endif

  //col *= 1.-dot(UV-=.5, UV); // vignette

  #ifdef HAS_HEART
   col = mix(pow(col, vec3(1.2, 1.2, 1.2)), col, heart);
   fade *= S(stimetotal, stimetotal-5, T);
  #endif

  col *= fade; // composite start and end fade
 #endif

 //col = vec3(heart,heart,heart);
 fragColor = vec4(col, 1);
 ret = fragColor;

  fragColor = ret;
}
